import{_ as o,o as r,c as a,ag as e,ah as n}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"使用统计","description":"","frontmatter":{},"headers":[],"relativePath":"features/usage-stats.md","filePath":"features/usage-stats.md"}'),s={name:"features/usage-stats.md"};function l(i,t,d,h,g,c){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="使用统计" tabindex="-1">使用统计 <a class="header-anchor" href="#使用统计" aria-label="Permalink to &quot;使用统计&quot;">​</a></h1><p>使用统计页面展示你在 LoongCode 中的 AI 调用历史，帮助你了解 Token 消耗量、活跃规律与常用模型，便于成本核对和使用习惯分析。数据完全来自本地历史文件，无需联网。</p><p>Token 是 AI 模型处理文本的计量单位（一段文字会被拆成若干 Token 处理），AI 服务的费用通常按 Token 数量计算，因此这里的用量也反映了你的使用成本。</p><blockquote><p>入口：<strong>设置 → 使用统计</strong></p></blockquote><div class="tip custom-block"><p class="custom-block-title">与「账号用量」是两回事</p><p>本页统计的是<strong>本地历史文件</strong>离线计算出的 Token 用量（可回看任意历史时间段），跟你用哪个账号登录无关；若想看 OAuth 账号当前<strong>实时</strong>的官方速率限额剩余量，请看<a href="/docs/settings/providers.html#账号用量">模型供应商 → 账号用量</a>（侧边栏也有对应的实时用量徽标）。</p></div><hr><h2 id="打开使用统计" tabindex="-1">打开使用统计 <a class="header-anchor" href="#打开使用统计" aria-label="Permalink to &quot;打开使用统计&quot;">​</a></h2><ol><li>点击左侧任务栏底部的<strong>设置</strong>按钮（齿轮图标）打开设置页。</li><li>在设置侧边栏中找到并点击<strong>使用统计</strong>。</li><li>页面首次打开时会自动扫描本地历史数据并加载，稍等片刻即可看到统计结果。</li></ol><p><img src="'+n+'" alt="截图：使用统计页面完整视图，数据已加载完毕，顶部显示「全部时间」区间选择器与 8 张指标卡，下方依次显示活跃热力图、按天 Token 趋势柱状图和模型用量表，突出指标卡与热力图区域，整体深色主题"></p><hr><h2 id="时间范围筛选" tabindex="-1">时间范围筛选 <a class="header-anchor" href="#时间范围筛选" aria-label="Permalink to &quot;时间范围筛选&quot;">​</a></h2><p>页面顶部提供三个时间范围选项（界面原文）：</p><ul><li><strong>全部时间</strong>（默认）：统计所有历史记录</li><li><strong>最近 30 天</strong>：仅统计近 30 天内的用量</li><li><strong>最近 7 天</strong>：仅统计近 7 天内的用量</li></ul><p>切换时间范围为本地即时计算，无需重新扫描，点击后立即刷新所有数据。页面右上角还提供<strong>刷新</strong>按钮，点击后重新扫描本地文件获取最新数据。</p><hr><h2 id="指标卡" tabindex="-1">指标卡 <a class="header-anchor" href="#指标卡" aria-label="Permalink to &quot;指标卡&quot;">​</a></h2><p>页面顶部区域以卡片形式展示 8 项关键指标：</p><table tabindex="0"><thead><tr><th>指标（界面原文）</th><th>含义</th></tr></thead><tbody><tr><td><strong>Token 用量</strong></td><td>选定范围内的输入 + 输出 Token 总量（不含缓存 Token）</td></tr><tr><td><strong>会话数</strong></td><td>在选定范围内有活动的会话数量</td></tr><tr><td><strong>消息数</strong></td><td>选定范围内的用户 + AI 消息总条数</td></tr><tr><td><strong>活跃天数</strong></td><td>选定范围内有实际调用的天数</td></tr><tr><td><strong>当前连续</strong></td><td>截至今天，连续活跃的天数</td></tr><tr><td><strong>最长连续</strong></td><td>历史最长连续活跃天数记录</td></tr><tr><td><strong>峰值时段</strong></td><td>一天中 Token 用量最集中的小时（以本地时间显示）</td></tr><tr><td><strong>最常用模型</strong></td><td>按 Token 占比排名第一的模型名称与其占比</td></tr></tbody></table><p>「当前连续」「最长连续」两个指标适合用来观察自己的使用习惯，例如是否保持了规律的开发节奏。</p><hr><h2 id="活跃热力图" tabindex="-1">活跃热力图 <a class="header-anchor" href="#活跃热力图" aria-label="Permalink to &quot;活跃热力图&quot;">​</a></h2><p>类似 GitHub 贡献图的日历热力图（界面标题：<strong>活跃热力图</strong>），每个格子代表一天：</p><ul><li>颜色深浅对应当天的 Token 用量，分为 5 个等级（从无到最深）</li><li>图例右下角标注「较少」与「较多」两端</li><li>鼠标悬浮在格子上可查看该日期与具体 Token 用量</li></ul><p>热力图直观展示你的使用周期和强度分布，帮你识别高峰时段和闲置期。</p><hr><h2 id="按天-token-趋势" tabindex="-1">按天 Token 趋势 <a class="header-anchor" href="#按天-token-趋势" aria-label="Permalink to &quot;按天 Token 趋势&quot;">​</a></h2><p>堆叠柱状图（界面标题：<strong>按天 Token 趋势</strong>），横轴为日期，纵轴为 Token 数量：</p><ul><li>每根柱子按模型分段着色，一眼看清同一天内各模型的用量占比</li><li>图表底部附有颜色图例，标注各模型名称</li></ul><p>这个图表适合用来观察用量的时间趋势，例如某段时间是否明显增多，或使用模型有无切换。</p><hr><h2 id="模型用量表" tabindex="-1">模型用量表 <a class="header-anchor" href="#模型用量表" aria-label="Permalink to &quot;模型用量表&quot;">​</a></h2><p>列表（界面标题：<strong>模型用量</strong>），按 Token 占比降序展示每个模型的详细数据：</p><ul><li><strong>模型名称</strong>：使用过的所有模型（含历史使用但当前未启用的）</li><li><strong>输入 / 输出明细</strong>：该模型的输入 Token 与输出 Token 分列显示</li><li><strong>占比</strong>：该模型 Token 量占选定范围总量的百分比</li></ul><p>模型用量表适合用来核对各模型的实际消耗比例，判断是否有模型用量异常偏高。</p><hr><h2 id="空状态与注意事项" tabindex="-1">空状态与注意事项 <a class="header-anchor" href="#空状态与注意事项" aria-label="Permalink to &quot;空状态与注意事项&quot;">​</a></h2><ul><li>如果选定范围内没有用量记录，各图区显示「当前区间暂无可展示的用量数据。」</li><li>统计数据来源于 <code>~/.claude/projects/</code> 目录下的本地历史文件，不含未通过 LoongCode 发起的调用。</li><li>子 Agent（子任务代理）的 Token 用量会计入总量、模型分布和热力图；会话数和消息数只统计主线对话。</li></ul><div class="tip custom-block"><p class="custom-block-title">如何降低用量</p><p>长对话会反复携带历史上下文，是 Token 消耗的主要来源。可以使用<a href="/docs/features/conversation.html">对话面板</a>中的手动压缩功能精简对话历史，或在<strong>设置 → 常规</strong>中保持「自动压缩」开启。</p></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>功能详解至此完结。接下来可以进入<a href="/docs/settings/general.html">常规设置</a>了解 LoongCode 的设置选项，对应用行为进行个性化配置。</p>',41)])])}const k=o(s,[["render",l]]);export{u as __pageData,k as default};
